# test_decrypt.py

import hashlib
import json
from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad

# 🔑 Ton .keydata (extrait de ton fichier .keydata.txt)
uuid = "f1a6be74597010cb4bc2413c5dfee1bb"
cipher_hex = ""

# Décode les parties
iv_hex, ciphertext_hex = cipher_hex.split("|")
iv = bytes.fromhex(iv_hex)
ciphertext = bytes.fromhex(ciphertext_hex)

# Calcule la clé : MD5(uuid)
key = hashlib.md5(uuid.encode("utf-8")).digest()

# Decrypte avec AES-CBC
cipher = AES.new(key, AES.MODE_CBC, iv)
decrypted_padded = cipher.decrypt(ciphertext)
decrypted = unpad(decrypted_padded, AES.block_size)

# Parse JSON
data = json.loads(decrypted.decode("utf-8"))

print("=" * 60)
print("✅ Déchiffrement réussi !")
print(f"UUID : {uuid}")
print("-" * 60)
for k, v in data.items():
    if isinstance(v, str) and len(v) > 40:
        print(f"{k[:15]}... = {v[:30]}...")
    else:
        print(f"{k} = {v}")
